import { useMutation, useQueryClient } from '@tanstack/react-query';

function DeleteProductButton({ productId }) {
  const queryClient = useQueryClient();

  const mutation = useMutation({
    mutationFn: (id) => fetch(`/api/products/${id}`, { method: 'DELETE' }).then(res => {
      if (!res.ok) throw new Error('Erreur lors de la suppression');
    }),
    onSuccess: () => {
      // Invalider le cache des produits pour déclencher un refetch
      queryClient.invalidateQueries({ queryKey: ['products'] });
    },
  });

  return (
    <button 
      onClick={() => mutation.mutate(productId)}
      disabled={mutation.isPending}
    >
      {mutation.isPending ? 'Suppression...' : 'Supprimer'}
    </button>
  );
}

const queryClient = useQueryClient();

const toggleMutation = useMutation({
  mutationFn: (todo) => fetch(`/api/todos/${todo.id}`, {
    method: 'PATCH',
    body: JSON.stringify({ completed: !todo.completed })
  }).then(res => {
    if (!res.ok) throw new Error('Erreur réseau');
    return res.json();
  }),

  onMutate: async (newTodo) => {
    // Annuler les requêtes en cours
    await queryClient.cancelQueries({ queryKey: ['todos'] });

    // Sauvegarder l'état précédent
    const previousTodos = queryClient.getQueryData(['todos']);

    // Mise à jour optimiste du cache
    queryClient.setQueryData(['todos'], (old) =>
      old.map(todo =>
        todo.id === newTodo.id 
          ? { ...todo, completed: !todo.completed }
          : todo
      )
    );

    return { previousTodos };
  },

  onError: (err, newTodo, context) => {
    // Rollback en cas d'erreur
    queryClient.setQueryData(['todos'], context.previousTodos);
  },

  onSettled: () => {
    // Revalider pour être sûr d'être à jour
    queryClient.invalidateQueries({ queryKey: ['todos'] });
  }
});
